+                };
+                make_scored_candidate(action, rng.next_f64() * 3.0)
+            })
+            .collect();
+
+        // Random sequence of operations.
+        for step in 0..20 {
+            let op = rng.next_u64() % 5;
+            match op {
+                0 => { engine.promote(); }
+                1 => { engine.demote(); }
+                2 => {
+                    engine.enter_fallback(FallbackReason::PolicyError {
+                        details: format!("seed={seed} step={step}"),
+                    });
+                }
+                3 => {
