+            // Invariant: mode is always valid.
+            let mode = engine.mode();
+            assert!(
+                matches!(
+                    mode,
+                    ActiveMode::Observe
+                        | ActiveMode::Canary
+                        | ActiveMode::Enforce
+                        | ActiveMode::FallbackSafe
+                ),
+                "seed={seed} step={step}: invalid mode"
+            );
+        }
+    }
